1	import { api } from './client';
2	
3	/**
4	 * Suites API — a suite is a named bundle of DQ checks bound to one connection.
5	 * `connection_id` is set at create and immutable thereafter (re-pointing would
6	 * orphan the child checks), mirroring the backend `suite_service` contract.
7	 */
8	
9	/** Mirrors the backend `SuiteRead` schema. */
10	export interface Suite {
11	  id: string;
12	  name: string;
13	  description: string | null;
14	  connection_id: string;
15	  /** Datasource-shaped run target (#215); null = not yet runnable. */
16	  target: Record<string, unknown> | null;
17	  created_by: string;
