      <h1 style={{ margin: 0, fontFamily: 'var(--font-sans)', fontSize: 24, fontWeight: 600, color: 'var(--text-primary)', letterSpacing: '-0.005em' }}>Results</h1>
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(4, 1fr)', gap: 16 }}>
        <MetricCard label="Pass Rate (7d)" value="94.2%" delta="+1.2%" trend="up" icon={<I.shield size={18} />} progress={94.2} />
        <MetricCard label="Runs (7d)" value="1,204" icon={<I.refresh size={18} />} footnote="Across 42 suites" />
        <MetricCard label="Open Anomalies" value="128" delta="-14%" trend="down" icon={<I.alert size={18} />} footnote="warn + fail + critical" />
        <MetricCard label="Avg. Duration" value="2.4h" delta="-20m" trend="down" icon={<I.clock size={18} />} />
      </div>
      <div>
        <Tabs value={tab} onChange={setTab} items={[{ key: 'runs', label: 'Runs' }, { key: 'pipelines', label: 'Pipeline runs' }]} />
        <div style={{ marginTop: 16 }}>{tab === 'runs' ? <RunsTab onOpen={(run) => go('run-detail', { run })} /> : <PipelinesTab />}</div>
      </div>
    </div>
  );
}

