    { key: 'status', header: 'Status', width: 96, render: (v) => <StatusBadge status={v} variant="soft" /> },
    { key: 'metric', header: 'Metric', align: 'right', width: 70, mono: true },
    { key: 'observed', header: 'Observed', mono: true, render: (v) => <span style={{ fontSize: 12, color: 'var(--text-body)' }}>{v}</span> },
  ];
  const passed = CHECK_RESULTS.filter((c) => c.status === 'pass').length;
  return (
    <div style={{ maxWidth: 1000, margin: '0 auto' }}>
      <PageHeader backLabel="Results" onBack={() => go('results')}
        title={run.suite} subtitle={<span style={{ fontFamily: 'var(--font-mono)' }}>{run.by || 'manual'}</span>}
        actions={<React.Fragment>
          <DownloadMenu run={run} />
          <Button variant="secondary" size="sm" iconLeft={<window.Icon.refresh size={14} />}>Re-run</Button>
        </React.Fragment>} />

      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(4, 1fr)', gap: 16, marginBottom: 20 }}>
        <Card padding={18}>
          <div style={{ fontSize: 13, color: 'var(--text-secondary)', marginBottom: 8 }}>Status</div>
          <StatusBadge status={run.status} variant="soft" />
        </Card>
        <MetricCard label="Checks passed" value={`${passed}/${CHECK_RESULTS.length}`} progress={(passed / CHECK_RESULTS.length) * 100} progressTone={passed === CHECK_RESULTS.length ? 'pass' : 'warning'} />
        <MetricCard label="Started" value={startParts[1] || startParts[0]} footnote={startParts[1] ? startParts[0] : null} />
        <MetricCard label="Duration" value={run.dur || '—'} />
      </div>

      <div style={{ fontSize: 16, fontWeight: 600, color: 'var(--text-primary)', marginBottom: 12 }}>Check results</div>
      <Card padding={0} style={{ overflow: 'hidden' }}><DataTable columns={cols} rows={CHECK_RESULTS} /></Card>
    </div>
  );
}

function PipelinesTab() {
  const { DataTable, StatusBadge, Tag } = DQ;
